#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
Gerador dos templos 11-50 — 5.000 palavras mais frequentes do italiano
Cada templo tem ~107-115 palavras organizadas tematicamente.
"""
import json, os, sys

OUT = os.path.dirname(os.path.abspath(__file__))

def salvar(templo_num, nome, cidade, nivel, palavras):
    obj = {"templo": templo_num, "nome": nome, "cidade": cidade, "nivel": nivel, "palavras": palavras}
    path = os.path.join(OUT, f"templo-{templo_num}.json")
    with open(path, "w", encoding="utf-8") as f:
        json.dump(obj, f, ensure_ascii=False, indent=2)
    print(f"OK templo-{templo_num}.json -- {len(palavras)} palavras")

def w(tid, it, pt, cat, ex_it, ex_pt, ipa="", gen=None, pl=None):
    return {"id": tid, "italiano": it, "portugues": pt, "genero": gen, "plural": pl,
            "exemplo": ex_it, "exemplo_pt": ex_pt, "categoria": cat,
            "dificuldade": "medio", "audio_ipa": ipa}

